"""Trust-constr optimization with analytical sparse Jacobians for circle packing n=26"""
import numpy as np
from scipy.optimize import minimize, NonlinearConstraint
from scipy.sparse import csr_matrix

def construct_packing():
    """Use trust-constr with analytical gradients for optimal circle packing."""
    n = 26
    x0 = _initial_hexagonal(n)
    bounds = [(0,1)]*2*n + [(1e-6, 0.5)]*n

    # Objective: minimize negative sum of radii
    def objective(v):
        return -np.sum(v[2*n:])

    def obj_grad(v):
        g = np.zeros(3*n)
        g[2*n:] = -1.0
        return g

    # All constraints combined
    def constraints(v):
        return np.concatenate([_boundary_con(v, n), _overlap_con(v, n)])

    def constraints_jac(v):
        return csr_matrix(np.vstack([_boundary_jac(v, n).toarray(), _overlap_jac(v, n).toarray()]))

    nlc = NonlinearConstraint(constraints, 0, np.inf, jac=constraints_jac)

    res = minimize(objective, x0, method='trust-constr', jac=obj_grad,
                   bounds=bounds, constraints=[nlc],
                   options={'maxiter': 2000, 'gtol': 1e-12, 'verbose': 0})

    centers = np.column_stack([res.x[:n], res.x[n:2*n]])
    radii = res.x[2*n:].copy()
    centers, radii = _ensure_validity(centers, radii)
    radii = _expand_radii(centers, radii)
    return centers, radii, np.sum(radii)

def _boundary_con(v, n):
    x, y, r = v[:n], v[n:2*n], v[2*n:]
    return np.concatenate([x-r, 1-x-r, y-r, 1-y-r])

def _boundary_jac(v, n):
    row, col, data = [], [], []
    for i in range(n):
        row.extend([i,i, n+i,n+i, 2*n+i,2*n+i, 3*n+i,3*n+i])
        col.extend([i,2*n+i, i,2*n+i, n+i,2*n+i, n+i,2*n+i])
        data.extend([1,-1, -1,-1, 1,-1, -1,-1])
    return csr_matrix((data, (row, col)), shape=(4*n, 3*n))

def _overlap_con(v, n):
    x, y, r = v[:n], v[n:2*n], v[2*n:]
    c = []
    for i in range(n):
        for j in range(i+1, n):
            d = np.sqrt((x[i]-x[j])**2 + (y[i]-y[j])**2)
            c.append(d - r[i] - r[j])
    return np.array(c)

def _overlap_jac(v, n):
    x, y, r = v[:n], v[n:2*n], v[2*n:]
    row, col, data = [], [], []
    k = 0
    for i in range(n):
        for j in range(i+1, n):
            dx, dy = x[i]-x[j], y[i]-y[j]
            d = np.sqrt(dx*dx + dy*dy)
            if d < 1e-10: d = 1e-10
            row.extend([k]*6)
            col.extend([i, j, n+i, n+j, 2*n+i, 2*n+j])
            data.extend([dx/d, -dx/d, dy/d, -dy/d, -1, -1])
            k += 1
    return csr_matrix((data, (row, col)), shape=(n*(n-1)//2, 3*n))

def _initial_hexagonal(n):
    x0 = np.zeros(3*n)
    rows = [5, 4, 5, 4, 5, 3]
    idx = 0
    for row, cnt in enumerate(rows):
        y = 0.1 + row * 0.145
        x_start = 0.1 if row % 2 == 0 else 0.175
        for j in range(cnt):
            x0[idx] = x_start + j * 0.17
            x0[n+idx] = y
            idx += 1
    x0[2*n:] = 0.095
    return x0

def _ensure_validity(centers, radii):
    n = len(radii)
    for i in range(n):
        radii[i] = min(radii[i], centers[i,0], centers[i,1], 1-centers[i,0], 1-centers[i,1])
    for _ in range(100):
        ok = True
        for i in range(n):
            for j in range(i+1, n):
                d = np.linalg.norm(centers[i]-centers[j])
                if radii[i]+radii[j] > d + 1e-10:
                    s = d / (radii[i]+radii[j]) * 0.9999
                    radii[i] *= s
                    radii[j] *= s
                    ok = False
        if ok: break
    return centers, radii

def _expand_radii(centers, radii):
    n = len(radii)
    for _ in range(200):
        expanded = False
        for i in range(n):
            max_r = min(centers[i,0], centers[i,1], 1-centers[i,0], 1-centers[i,1])
            for j in range(n):
                if i != j:
                    max_r = min(max_r, np.linalg.norm(centers[i]-centers[j]) - radii[j])
            max_r = max(max_r, 1e-8)
            if max_r > radii[i] + 1e-8:
                radii[i] = max_r * 0.9999
                expanded = True
        if not expanded: break
    return radii
